    {
      "keystrokes": "cd /git/server\n",
      "duration": 0.1
    },
    {
      "keystrokes": "git config --global user.email \"test@example.com\"\n",
      "duration": 0.1
    },
    {
      "keystrokes": "git config --global user.name \"Test User\"\n",
      "duration": 0.1
