    {
      "keystrokes": "cd testclone\n",
      "duration": 0.1
    },
    {
      "keystrokes": "echo \"hello world\" > hello.html\n",
      "duration": 0.1
    },
    {
      "keystrokes": "git add hello.html\n",
      "duration": 0.1
    },
    {
      "keystrokes": "git commit -m \"add hello.html\"\n",
      "duration": 1.0
    },
    {
      "keystrokes": "git push origin master\n",
      "duration": 1.0
    },
    {
      "keystrokes": "sleep 1\n",
      "duration": 1.0
    },
    {
      "keystrokes": "# Verify file exists in web directory\n",
      "keystrokes": "cat /var/www/git-server/hello.html\n",
      "duration": 0.1
    },
    {
      "keystrokes": "# Test curl\n",
      "keystrokes": "curl -s http://localhost:8080/hello.html\n",
      "duration": 1.0
    }
  ],
  "task_complete": false
}

